import numpy as np

class Metaheuristic:

    def __init__(self, func, dim, bounds, budget, n_obj):
        self.func   = func
        self.dim    = dim
        self.bounds = bounds
        self.budget = budget
        self.n_obj  = n_obj

    def solve(self):
        lo, hi = self.bounds[0], self.bounds[1]
        archive_x, archive_f = [], []

        # Initial random population (10% of budget)
        pop_size = max(1, self.budget // 10)
        for _ in range(pop_size):
            x = lo + (hi - lo) * np.random.rand(self.dim)
            f = self.func(x)
            archive_x.append(x.copy())
            archive_f.append(f.copy())

        remaining = self.budget - pop_size
        for _ in range(remaining):
            # Pick a random parent from current non-dominated solutions
            if len(archive_x) > 0:
                parent_idx = np.random.randint(len(archive_x))
                parent = archive_x[parent_idx]
            else:
                parent = lo + (hi - lo) * np.random.rand(self.dim)

            # Mutation: polynomial mutation
            child = parent.copy()
            for j in range(self.dim):
                if np.random.rand() < 1.0 / self.dim:
                    r = np.random.rand()
                    if r < 0.5:
                        delta = (2 * r) ** (1/(20+1)) - 1
                    else:
                        delta = 1 - (2 * (1 - r)) ** (1/(20+1))
                    child[j] = parent[j] + delta * (hi[j] - lo[j])
                    child[j] = np.clip(child[j], lo[j], hi[j])

            f_child = self.func(child)

            # Check if child dominates or is non-dominated with archive
            dominated = False
            for i in range(len(archive_f)):
                if np.all(archive_f[i] <= f_child) and np.any(archive_f[i] < f_child):
                    dominated = True
                    break
            if not dominated:
                # Remove solutions dominated by child
                new_archive_x = [archive_x[i] for i in range(len(archive_x)) if not (np.all(f_child <= archive_f[i]) and np.any(f_child < archive_f[i]))]
                new_archive_f = [archive_f[i] for i in range(len(archive_f)) if not (np.all(f_child <= archive_f[i]) and np.any(f_child < archive_f[i]))]
                new_archive_x.append(child.copy())
                new_archive_f.append(f_child.copy())
                archive_x = new_archive_x
                archive_f = new_archive_f

        if len(archive_x) == 0:
            return np.empty((0, self.dim))
        return np.array(archive_x)

import numpy as np

class Metaheuristic:

    def __init__(self, func, dim, bounds, budget, n_obj):
        self.func   = func
        self.dim    = dim
        self.bounds = bounds
        self.budget = budget
        self.n_obj  = n_obj

    def solve(self):
        lo, hi = self.bounds[0], self.bounds[1]
        # Initial population size (use 20% of budget)
        pop_size = max(4, self.budget // 5)
        X = lo + (hi - lo) * np.random.rand(pop_size, self.dim)
        F = np.array([self.func(x) for x in X])
        evals = pop_size

        # Main loop
        while evals < self.budget:
            # Non-dominated sorting and crowding distance
            fronts = self._non_dominated_sort(F)
            # Select parents from first front
            front1 = fronts[0]
            if len(front1) < 2:
                # Random restart if too few solutions
                idx = np.random.choice(pop_size, 2, replace=False)
            else:
                idx = np.random.choice(front1, 2, replace=False)
            parent1, parent2 = X[idx[0]], X[idx[1]]

            # Differential evolution mutation
            a = np.random.choice([i for i in range(pop_size) if i not in idx])
            mutant = X[a] + 0.5 * (parent1 - parent2)
            mutant = np.clip(mutant, lo, hi)

            # Crossover with parent1
            child = parent1.copy()
            cr = 0.9
            for j in range(self.dim):
                if np.random.rand() < cr:
                    child[j] = mutant[j]

            # Evaluate child
            f_child = self.func(child)
            evals += 1

            # Replace worst in population if child is better
            # Find index of worst (most dominated, then largest crowding distance)
            worst_idx = self._find_worst(X, F)
            if self._dominates(f_child, F[worst_idx]):
                X[worst_idx] = child
                F[worst_idx] = f_child
            elif not np.any(F[worst_idx] <= f_child):
                # Non-dominated case: replace if child has better crowding
                if np.random.rand() < 0.5:
                    X[worst_idx] = child
                    F[worst_idx] = f_child

        # Return non-dominated set from final population
        nd = self._get_non_dominated(F)
        return X[nd]

    def _non_dominated_sort(self, F):
        n = len(F)
        fronts = []
        assigned = np.zeros(n, dtype=bool)
        while not assigned.all():
            front = []
            for i in range(n):
                if assigned[i]:
                    continue
                dominated = False
                for j in range(n):
                    if assigned[j] or i == j:
                        continue
                    if np.all(F[j] <= F[i]) and np.any(F[j] < F[i]):
                        dominated = True
                        break
                if not dominated:
                    front.append(i)
            fronts.append(front)
            for i in front:
                assigned[i] = True
        return fronts

    def _dominates(self, f1, f2):
        return np.all(f1 <= f2) and np.any(f1 < f2)

    def _find_worst(self, X, F):
        # Find index of solution with worst crowding distance in last front
        fronts = self._non_dominated_sort(F)
        last_front = fronts[-1]
        if len(last_front) == 0:
            return np.random.randint(len(F))
        # Compute crowding distance for last front
        if len(last_front) == 1:
            return last_front[0]
        F_last = F[last_front]
        crowding = np.zeros(len(last_front))
        for m in range(self.n_obj):
            order = np.argsort(F_last[:, m])
            crowding[order[0]] = np.inf
            crowding[order[-1]] = np.inf
            for i in range(1, len(order)-1):
                crowding[order[i]] += (F_last[order[i+1], m] - F_last[order[i-1], m])
        # Return index with smallest crowding distance
        return last_front[np.argmin(crowding)]

    def _get_non_dominated(self, F):
        n = len(F)
        nd = np.ones(n, dtype=bool)
        for i in range(n):
            if not nd[i]:
                continue
            for j in range(n):
                if i == j or not nd[j]:
                    continue
                if np.all(F[j] <= F[i]) and np.any(F[j] < F[i]):
                    nd[i] = False
                    break
        return nd
